import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Installer Fabric","description":"Un guide pour installer Fabric pas à pas.","frontmatter":{"title":"Installer Fabric","description":"Un guide pour installer Fabric pas à pas.","authors":["Benonardo","IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"fr_fr/1.21.4/players/installing-fabric.md","filePath":"versions/1.21.4/translated/fr_fr/players/installing-fabric.md","lastUpdated":1760721669000}`);var c={name:`fr_fr/1.21.4/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installer Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Installer Fabric”">​</a></h1><p>Ce guide ne s&#39;applique qu&#39;au launcher Minecraft officiel. Pour les lanceurs tiers, vous devriez consulter leur documentation.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Télécharger l&#39;installateur Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Télécharger l&#39;installateur Fabric”">​</a></h2><p>Vous pouvez télécharger l&#39;installateur Fabric depuis le <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">site de Fabric</a>.</p><p>Si vous utilisez Windows, téléchargez la version <code>.exe</code> (<code>Download For Windows</code>) car elle ne requiert pas d&#39;avoir installé Java sur votre système. Elle utilise à la place le Java fourni avec le launcher officiel.</p><p>Pour macOS et Linux, vous devrez télécharger la version <code>.jar</code>. Parfois, il vous faudra aussi installer Java avant cette étape.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Lancer l&#39;installateur Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Lancer l&#39;installateur Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Fermez Minecraft et le launcher avant de lancer l&#39;installation.</p></div><details class="details custom-block"><summary>Information pour les utilisateurs de MacOS</summary><p>Sur macOS, vous devrez peut-être faire un clic droit sur le fichier <code>.jar</code> dans votre répertoire de téléchargements et cliquer sur <code>Ouvrir</code> pour l&#39;exécuter.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu de l&#39;installateur Fabric sur MacOS" loading="lazy"></p><p>Lorsqu&#39;on vous demande « Êtes-vous sûr de vouloir l&#39;ouvrir ? », cliquez sur « Ouvrir ».</p></details><p>Une fois l&#39;installateur ouvert, vous devriez voir un écran comme celui-ci :</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Installateur Fabric avec &quot;Install&quot; de mis en avant" loading="lazy"></p><p>Pour installer Fabric, choisissez la version du jeu depuis le menu déroulant et cliquez sur <code>Installer</code>.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Assurez-vous que &#39;Créer un profil&#39; est coché.</p></div><h2 id="3-you-re-done" tabindex="-1">3. Et voilà ! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Et voilà !”">​</a></h2><p>Lorsque l&#39;installeur a terminé, vous pouvez ouvrir le lanceur Minecraft et sélectionner le profil Fabric dans le menu déroulant en bas à gauche. Appuyez ensuite sur Jouer !</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher Minecraft avec le profil Fabric sélectionné" loading="lazy"></p><p>Maintenant que vous avez installé Fabric, vous pouvez ajouter des mods à votre jeu ! Consultez le guide <a href="./finding-mods">Trouver des mods</a> pour plus d&#39;informations.</p><p>Si vous rencontrez des problèmes en suivant ce guide, vous pouvez demander de l&#39;aide dans le <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a> dans le salon <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};